#include <iostream>
#include <vector>
#include <string>
#include <cstring>

// Assume countWords function is defined above

struct TestCase {
    const char* input;
    int expected;
};

int main() {
    std::vector<TestCase> testCases = {
        {"hello world", 2},
        {"hello", 1},
        {"one two three", 3},
        {"", 0},
        {"single", 1},
        {"a b c d e", 5}
    };

    // Adding a test case for nullptr to specifically trigger the semantic error
    testCases.push_back({nullptr, 0});

    for (const auto& tc : testCases) {
        // const_cast is used because countWords takes char*
        // In a real scenario, countWords should take const char* if it doesn't modify.
        int result = countWords(const_cast<char*>(tc.input));
        std::cout << "Input: \"" << (tc.input ? tc.input : "nullptr") << "\", Expected: " << tc.expected
                  << ", Got: " << result << " -> "
                  << (result == tc.expected ? "PASSED" : "FAILED") << std::endl;
    }
    return 0;
}
